package com.careeros.documents.infrastructure;import org.springframework.stereotype.Component;import java.io.*;import java.nio.charset.StandardCharsets;import java.time.Duration;import java.util.*;import java.util.concurrent.*;@Component public class ProcessRunner{public Result run(List<String>command,String stdin,Duration timeout){try{Process p=new ProcessBuilder(command).redirectErrorStream(false).start();if(stdin!=null)try(var w=p.outputWriter(StandardCharsets.UTF_8)){w.write(stdin);}else p.getOutputStream().close();CompletableFuture<String>out=read(p.getInputStream()),err=read(p.getErrorStream());if(!p.waitFor(timeout.toMillis(),TimeUnit.MILLISECONDS)){p.destroyForcibly();throw new IllegalStateException("Process timed out after "+timeout);}String stdout=out.join(),stderr=err.join();if(p.exitValue()!=0)throw new IllegalStateException("Process failed ("+p.exitValue()+"): "+stderr);return new Result(stdout,stderr);}catch(IOException e){throw new IllegalStateException("Unable to start process: "+command.getFirst()+". "+e.getMessage(),e);}catch(InterruptedException e){Thread.currentThread().interrupt();throw new IllegalStateException("Process interrupted",e);}}private CompletableFuture<String>read(InputStream in){return CompletableFuture.supplyAsync(()->{try{return new String(in.readAllBytes(),StandardCharsets.UTF_8);}catch(IOException e){throw new UncheckedIOException(e);}});}public record Result(String stdout,String stderr){} }
